/**
 * Classification Pipeline Orchestrator
 *
 * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
 * (email, session, result, config) => void
 *
 * Pipeline Stages:
 * 1. Hard Assertions - Domain-based high-confidence categorization
 * 2. Strong Indicators - Weighted seed scoring with diminishing returns
 * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
 * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
 * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
 * 6. Disambiguation - Pairwise conflict resolution for close scores
 * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
 * 8. AI Routing - Selective AI classification for uncertain cases
 * 9. Final Decision - Label assignment and action determination
 * 10. Audit Trail - Complete explainability trace generation
 */

import { CategoryConfiguration } from '../types/category-configuration';
import { ClassificationResult } from '../types/classification-result';
import { ClassificationSession } from '../types/classification-session';
import { EmailMessage } from '../types/email-message';

// Validation utilities
import { validateConfigInput, validateEmailInput } from '../utils/validation';

// Domain lookup loader
import { DomainLookup, loadDomainLookup } from '../config/domain-resolver';

// Initialization utilities
import {
  createClassificationResult,
  createClassificationSession,
  finalizeClassificationSession,
  incrementSessionError,
  incrementSessionSuccess,
} from '../utils/initialization';

// Pipeline stages (canonical signatures)
import { actionDeterminationStage } from '../stages/action-determination';
import { aiClassificationStage } from '../stages/ai-classification';
import { aiFeatureExtractionStage } from '../stages/ai-feature-extraction';
import { aiLabelFilteringStage } from '../stages/ai-label-filtering';
import { aiRoutingStage } from '../stages/ai-routing';
import { executeAttributeDetection } from '../stages/attribute-detection';
import { executeAttributeInfluence } from '../stages/attribute-influence';
import { executeDisambiguation } from '../stages/disambiguation';
import { executeHardAssertions } from '../stages/hard-assertions';
import { executeMultiLabelSelection } from '../stages/multi-label-selection';
import { executeRuleScoring } from '../stages/rule-scoring';
import { executeStrongIndicators } from '../stages/strong-indicators';
// import { generateAuditTrail } from '../stages/audit-trail'; // TODO (T052): Wire audit trail after PipelineOutput/ClassificationResult architectural refactoring decision (see T052 re-evaluation criteria in tasks.md)

// Stage-specific config types
import type { ActionDeterminationConfig } from '../stages/action-determination';
import type { AIClassificationConfig } from '../stages/ai-classification';
import type { AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
import type { AILabelFilteringConfig } from '../stages/ai-label-filtering';
import type { AIRoutingConfig } from '../stages/ai-routing';
import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
import type { HardAssertionStageConfig } from '../stages/hard-assertions';
import type { RuleScoringStageConfig } from '../stages/rule-scoring';
import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
import type { ConfidenceThresholds, MultiLabelConfig } from '../stages/types';
// import type { AuditTrailConfig } from '../stages/audit-trail'; // TODO (T052): Wire audit trail config after PipelineOutput/ClassificationResult architectural refactoring decision (see T052 re-evaluation criteria in tasks.md)

/**
 * Pipeline stage execution order for replay functionality
 */
const STAGE_ORDER = [
  'hard-assertions',
  'strong-indicators',
  'rule-scoring',
  'attribute-detection',
  'attribute-influence',
  'disambiguation',
  'multi-label-selection',
  'ai-routing',
  'ai-feature-extraction',
  'ai-classification',
  'ai-label-filtering',
  'action-determination',
] as const;

/**
 * Stage task interface for replay-from-stage support
 *
 * Wraps individual pipeline stage functions to enable selective execution
 * based on replay parameters while maintaining minimal disruption to existing code.
 */
interface StageTask {
  /**
   * Stage identifier for replay functionality
   */
  name: string;

  /**
   * Execute the stage with canonical signature pattern
   *

   *
   * @param email - Email message to process
   * @param session - Classification session context
   * @param result - Mutable classification result (modified in place)
   * @param config - Stage-specific configuration
   */
  execute(
    email: EmailMessage,
    session: ClassificationSession,
    result: ClassificationResult,
    config: CategoryConfiguration
  ): Promise<void>;

  /**
   * Determine if this stage should be skipped for replay functionality
   *
   * @param replayFromStage - Optional stage to start replay from
   * @returns true if stage should be skipped, false to execute
   */
  shouldSkip(replayFromStage?: string): boolean;
}

/**
 * Error result for batch processing when individual email fails
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

