constructor(config: CategoryConfiguration, testMode: boolean = false) {
  // Validate processing configuration
  validateConfigInput(config.processingConfig);

  // Validate multi-label selection thresholds
  const multiLabelSettings = config.processingConfig.settings.multiLabelSelection;
  if (
    !multiLabelSettings ||
    multiLabelSettings.highConfidenceThreshold < 0 ||
    multiLabelSettings.mediumConfidenceThreshold < 0 ||
    multiLabelSettings.lowConfidenceThreshold < 0 ||
    multiLabelSettings.secondaryLabelMinGap < 0
  ) {
    throw new Error('Invalid multi-label selection thresholds: all values must be non-negative');
  }

  this.config = config;
  this.testMode = testMode;

  // Load domain lookup from config/domain-sources.json
  // Gracefully handles missing/malformed files by returning empty lookup
  this.domainLookup = loadDomainLookup();
}

/**
 * Get configuration (for testing and future stage integration)
 */
getConfig(): CategoryConfiguration {
  return this.config;
}

/**
 * Helper function to determine if a stage should be skipped for replay
 *
 * @param stageName - Name of the current stage
 * @param replayFromStage - Stage to start replay from (optional)
 * @returns true if stage should be skipped, false to execute
 */
private shouldSkipStage(stageName: string, replayFromStage?: string): boolean {
  if (!replayFromStage) return false;
  const replayIndex = STAGE_ORDER.indexOf(replayFromStage as (typeof STAGE_ORDER)[number]);
  const currentIndex = STAGE_ORDER.indexOf(stageName as (typeof STAGE_ORDER)[number]);
  return replayIndex !== -1 && currentIndex < replayIndex;
}

/**
 * Stage configuration mapping for factory pattern
 */
private readonly stageConfigs = {
  'hard-assertions': () => this.getHardAssertionConfig(),
  'strong-indicators': () => this.getStrongIndicatorConfig(),
  'rule-scoring': () => this.getRuleScoringConfig(),
  'attribute-detection': () => this.getAttributeDetectionConfig(),
  'attribute-influence': () => this.config,
  disambiguation: () => this.config,
  'multi-label-selection': () => ({
    multiLabel: this.getMultiLabelConfig(),
    confidenceThresholds: this.getConfidenceThresholds(),
  }),
  'ai-routing': () => this.getAIRoutingConfig(),

/**
 * Shared Validation Utilities
 *
 * Common validation functions used across pipeline stages to ensure consistent
 * error handling and input validation. Extracted from duplicate validation logic
 * in ai-routing.ts, final-decision.ts, disambiguation.ts, and audit-trail.ts.
 *
 * Benefits:
 * - Consistent error messages across all stages
 * - Reduced code duplication
 * - Single source of truth for validation rules
 * - Easier to maintain and update validation logic
 */

import { EmailMessage, ClassificationSession } from '../types';

/**
 * Validate email input parameter
 *
 * Ensures email has either `id` or `gmailId` field required for processing.
 * Used by stages that need to reference specific email messages.
 *
 * @param email - Email message to validate
 * @throws Error if email is null, undefined, or missing required fields
 */
export function validateEmailInput(email: EmailMessage): void {
  if (!email || (!email.id && !(email as unknown as Record<string, unknown>).gmailId)) {
    throw new Error('Invalid email input: id or gmailId is required');
  }
}

/**
 * Validate classification session input parameter
 *
 * Ensures session has either `id` or `sessionId` field required for tracking.
 * Used by stages that need to reference specific classification sessions.
 *
 * @param session - Classification session to validate
 * @throws Error if session is null, undefined, or missing required fields
 */
export function validateSessionInput(session: ClassificationSession): void {
  if (!session || (!session.id && !(session as unknown as Record<string, unknown>).sessionId)) {
    throw new Error('Invalid session input: id or sessionId is required');
  }
}

/**
 * Validate configuration input parameter
 *
 * Ensures configuration is a valid object (not null, undefined, or primitive types).
 * Used by all stages that require configuration parameters.
 *
 * @param config - Configuration object to validate
 * @throws Error if config is null, undefined, or not an object
 */
export function validateConfigInput(config: unknown): void {
  if (!config || typeof config !== 'object' || Array.isArray(config)) {
    throw new Error('Configuration is required');
  }
}

/**
 * Validate confidence score value
 *
 * Ensures confidence score is a finite number (not NaN, Infinity, or -Infinity).
 * Does NOT enforce range constraints (scores can be negative or > 1 in some contexts).
 *
 * @param score - Confidence score to validate
 * @throws Error if score is NaN or infinite
 */
export function validateConfidenceScore(score: number): void {
  if (isNaN(score) || !isFinite(score)) {
    throw new Error('Invalid confidence score');
  }
}

/**
 * Validate confidence threshold value
 *
 * Ensures threshold is a finite number within [0, 1] range.
 * Used for configuration validation where thresholds must be probabilities.
 *
 * @param threshold - Confidence threshold to validate
 * @throws Error if threshold is invalid or outside [0, 1] range
 */
export function validateConfidenceThreshold(threshold: number): void {
  if (isNaN(threshold) || !isFinite(threshold) || threshold < 0 || threshold > 1) {
    throw new Error('Invalid confidence threshold');
  }
}

